import torch
import torch.nn as nn
import torch.nn.functional as F
import numpy as np

class SimpleCLIP(nn.Module):
    def __init__(self, embed_dim=512):
        super().__init__()
        self.image_encoder = nn.Sequential(
            nn.Conv2d(3, 64, 3, padding=1), nn.ReLU(), nn.MaxPool2d(2),
            nn.Conv2d(64, 128, 3, padding=1), nn.ReLU(), nn.MaxPool2d(2),
            nn.Flatten(), nn.Linear(128 * 8 * 8, embed_dim)
        )
        self.text_embed = nn.Embedding(1000, 128)
        self.text_lstm = nn.LSTM(128, 256, batch_first=True)
        self.text_proj = nn.Linear(256, embed_dim)

    def encode_image(self, images):
        return F.normalize(self.image_encoder(images), dim=-1)

    def encode_text(self, tokens):
        x = self.text_embed(tokens)
        x, _ = self.text_lstm(x)
        x = self.text_proj(x[:, -1])
        return F.normalize(x, dim=-1)

class TextImageRetrieval:
    def __init__(self):
        self.images = {
            "cat_sitting.jpg": [0.8, 0.1, 0.2],
            "dog_running.jpg": [0.1, 0.9, 0.1],
            "red_car.jpg": [0.2, 0.1, 0.8],
            "beach_sunset.jpg": [0.7, 0.2, 0.3],
            "cat_playing.jpg": [0.85, 0.05, 0.1]
        }

    def text_to_vector(self, text):
        embeddings = {"cat": [0.8, 0.1, 0.2], "dog": [0.1, 0.9, 0.1],
                      "car": [0.2, 0.1, 0.8], "beach": [0.7, 0.2, 0.3]}
        for word, vec in embeddings.items():
            if word in text.lower():
                return vec
        return [0.5, 0.5, 0.5]

    def search(self, query, top_k=3):
        query_vec = self.text_to_vector(query)
        similarities = []
        for img, vec in self.images.items():
            sim = np.dot(query_vec, vec) / (np.linalg.norm(query_vec) * np.linalg.norm(vec))
            similarities.append((img, sim))
        similarities.sort(key=lambda x: x[1], reverse=True)
        return similarities[:top_k]

class ImageCaptioner:
    def __init__(self):
        self.captions = {
            "cat": ["A cute cat sitting on a couch.", "A fluffy cat playing with a ball."],
            "dog": ["A dog running in the park.", "A happy dog wagging its tail."],
            "car": ["A red sports car parked on the street.", "A modern electric vehicle."],
            "beach": ["A beautiful sunset at the beach.", "Waves crashing on the shore."]
        }

    def caption(self, image_features):
        if max(image_features) == image_features[0]:
            return self.captions["cat"][0]
        elif max(image_features) == image_features[1]:
            return self.captions["dog"][0]
        elif max(image_features) == image_features[2]:
            return self.captions["car"][0]
        else:
            return self.captions["beach"][0]

class VQAModel:
    def answer(self, image_features, question):
        q = question.lower()
        if "color" in q and max(image_features) == image_features[2]:
            return "red" if "car" in q else "blue"
        elif "doing" in q and max(image_features) == image_features[0]:
            return "sitting on a couch"
        elif "where" in q and max(image_features) == image_features[3]:
            return "at the beach"
        else:
            return "I see a " + ["cat", "dog", "car", "beach"][np.argmax(image_features)]

class ZeroShotClassifier:
    def classify(self, image_features, class_names):
        class_embeds = {"cat": [0.8, 0.1, 0.2], "dog": [0.1, 0.9, 0.1], "car": [0.2, 0.1, 0.8]}
        scores = {}
        for name in class_names:
            sim = np.dot(image_features, class_embeds[name]) / (
                np.linalg.norm(image_features) * np.linalg.norm(class_embeds[name])
            )
            scores[name] = sim
        return max(scores, key=scores.get)

print("🎨 Text + Image Models Demonstration")
print("=" * 50)
retriever = TextImageRetrieval()
results = retriever.search("cat playing", top_k=2)
print(f"📷 Text-to-Image Retrieval: 'cat playing'")
for img, score in results:
    print(f"  {img}: similarity={score:.3f}")
captioner = ImageCaptioner()
img_features = [0.85, 0.05, 0.1, 0.0]
caption = captioner.caption(img_features)
print(f"\n📝 Image Captioning: {caption}")
vqa = VQAModel()
answer = vqa.answer([0.2, 0.1, 0.8, 0.0], "What color is the car?")
print(f"\n❓ VQA: Q: 'What color is the car?' → A: '{answer}'")
classifier = ZeroShotClassifier()
result = classifier.classify([0.85, 0.05, 0.1], ["cat", "dog", "car"])
print(f"\n🎯 Zero-shot Classification: Image classified as '{result}'")
print("\n✅ Multimodal AI Capabilities:")
print("  • Text-to-Image Retrieval: Find images matching text")
print("  • Image Captioning: Describe images in words")
print("  • Visual Question Answering: Answer questions about images")
print("  • Zero-shot Classification: Classify with text labels")
print("  • Shared Embeddings: Compare text and images directly")
